parameters.jsCode:
const subject = $input.item.json.subject || '';
const body = $input.item.json.snippet || '';
const text = subject + ' ' + body;
const ticker = text.match(/BUY\s+([A-Z]+)/)?.[1] || 'UNKNOWN';
const price = parseFloat(text.match(/Price:\s*([\d.]+)/)?.[1] || 0);
const stop = (price * 0.92).toFixed(2);
const t1 = (price * 1.15).toFixed(2);
const t2 = (price * 1.30).toFixed(2);
const t3 = (price * 1.60).toFixed(2);
return [{ json: { ticker, price, stop, t1, t2, t3 } }];

